// src/screens/ProgresoScreen.js
import React, { useState, useEffect, useCallback } from 'react';
import {
  View, Text, ScrollView, TouchableOpacity,
  StyleSheet, TextInput, Alert,
} from 'react-native';
import { useFocusEffect } from '@react-navigation/native';
import { colors, radius, spacing } from '../utils/theme';
import {
  loadProgress, saveProgress,
  loadSleepLog, saveSleepLog,
  loadStartDate, loadPerfil,
} from '../utils/storage';
import { RUTINAS } from '../data/routines';

const DAYS_ABBR = ['Lu', 'Ma', 'Mi', 'Ju', 'Vi', 'Sá', 'Do'];

function SleepBar({ hours, maxHours = 10, isToday }) {
  const pct = hours ? Math.min(hours / maxHours, 1) : 0;
  return (
    <View style={bar.wrap}>
      <View style={bar.track}>
        <View style={[bar.fill, { height: `${pct * 100}%`, backgroundColor: isToday ? colors.accent : colors.accentSoft }]} />
      </View>
      <Text style={bar.label}>{hours ? `${hours}h` : '—'}</Text>
    </View>
  );
}

const bar = StyleSheet.create({
  wrap: { flex: 1, alignItems: 'center', paddingHorizontal: 2 },
  track: { width: '100%', height: 80, backgroundColor: colors.bgElevated, borderRadius: 4, justifyContent: 'flex-end', overflow: 'hidden' },
  fill: { width: '100%', borderRadius: 4 },
  label: { fontSize: 9, color: colors.textMuted, marginTop: 3 },
});

export default function ProgresoScreen() {
  const [progress, setProgress]   = useState(new Array(14).fill(false));
  const [sleepLog, setSleepLog]   = useState(new Array(14).fill(null));
  const [perfil, setPerfil]       = useState(null);
  const [startDate, setStartDate] = useState(null);
  const [logInput, setLogInput]   = useState('');
  const [todayIdx, setTodayIdx]   = useState(0);

  useFocusEffect(
    useCallback(() => {
      Promise.all([loadProgress(), loadSleepLog(), loadStartDate(), loadPerfil()])
        .then(([prog, log, start, perf]) => {
          setProgress(prog);
          setSleepLog(log);
          setPerfil(perf);
          if (start) {
            setStartDate(new Date(start));
            const diffMs = Date.now() - new Date(start).getTime();
            const diffDays = Math.floor(diffMs / 86400000);
            setTodayIdx(Math.min(diffDays, 13));
          }
        });
    }, [])
  );

  const toggleDay = async (idx) => {
    const updated = [...progress];
    updated[idx] = !updated[idx];
    setProgress(updated);
    await saveProgress(updated);
  };

  const logSleep = async () => {
    const h = parseFloat(logInput);
    if (!h || h <= 0 || h > 14) {
      Alert.alert('Valor inválido', 'Ingresa un número entre 1 y 14 horas.');
      return;
    }
    const updated = [...sleepLog];
    updated[todayIdx] = h;
    setSleepLog(updated);
    await saveSleepLog(updated);
    setLogInput('');
  };

  // Métricas
  const done = progress.filter(Boolean).length;
  const pct  = Math.round((done / 14) * 100);

  let racha = 0;
  for (let i = todayIdx; i >= 0; i--) { if (progress[i]) racha++; else break; }

  const avgSleep = (() => {
    const filled = sleepLog.filter(h => h !== null);
    if (!filled.length) return null;
    return (filled.reduce((a, b) => a + b, 0) / filled.length).toFixed(1);
  })();

  const statusColor = pct >= 70 ? colors.success : pct >= 40 ? colors.warn : colors.danger;
  const statusLabel = pct >= 70 ? '¡Excelente progreso!' : pct >= 40 ? 'Buen esfuerzo' : 'Apenas iniciando';

  const rutina = perfil ? RUTINAS[perfil] : null;

  return (
    <ScrollView style={s.scroll} contentContainerStyle={s.container} showsVerticalScrollIndicator={false}>

      {/* Header resumen */}
      <View style={s.summaryCard}>
        <View style={[s.statusPill, { backgroundColor: statusColor + '22' }]}>
          <View style={[s.statusDot, { backgroundColor: statusColor }]} />
          <Text style={[s.statusLabel, { color: statusColor }]}>{statusLabel}</Text>
        </View>
        {rutina && (
          <Text style={s.perfilText}>Perfil: {rutina.label} {rutina.emoji}</Text>
        )}
        <Text style={s.pctBig}>{pct}%</Text>
        <View style={s.trackBg}>
          <View style={[s.trackFill, { width: `${pct}%`, backgroundColor: statusColor }]} />
        </View>
        <Text style={s.pctSub}>{done} de 14 días completados</Text>
      </View>

      {/* Métricas */}
      <View style={s.metricRow}>
        <View style={s.metric}>
          <Text style={s.metricVal}>{racha}</Text>
          <Text style={s.metricLabel}>Racha actual{'\n'}(días)</Text>
        </View>
        <View style={s.metric}>
          <Text style={s.metricVal}>{avgSleep ?? '—'}</Text>
          <Text style={s.metricLabel}>Promedio de{'\n'}sueño (h)</Text>
        </View>
        <View style={s.metric}>
          <Text style={s.metricVal}>{14 - done}</Text>
          <Text style={s.metricLabel}>Días{'\n'}restantes</Text>
        </View>
      </View>

      {/* Calendario */}
      <Text style={s.sectionLabel}>Semana 1</Text>
      <View style={s.weekGrid}>
        {Array.from({ length: 7 }).map((_, d) => {
          const isDone  = progress[d];
          const isToday = d === todayIdx;
          return (
            <TouchableOpacity
              key={d}
              style={[s.dayCell, isDone && s.dayCellDone, isToday && s.dayCellToday]}
              onPress={() => toggleDay(d)}
              activeOpacity={0.7}
            >
              <Text style={[s.dayAbbr, isDone && s.dayAbbrDone]}>{DAYS_ABBR[d]}</Text>
              <Text style={[s.dayNum, isDone && s.dayNumDone]}>{d + 1}</Text>
              {isDone && <Text style={s.checkmark}>✓</Text>}
            </TouchableOpacity>
          );
        })}
      </View>

      <Text style={[s.sectionLabel, { marginTop: spacing.md }]}>Semana 2</Text>
      <View style={s.weekGrid}>
        {Array.from({ length: 7 }).map((_, d) => {
          const idx     = d + 7;
          const isDone  = progress[idx];
          const isToday = idx === todayIdx;
          return (
            <TouchableOpacity
              key={idx}
              style={[s.dayCell, isDone && s.dayCellDone, isToday && s.dayCellToday]}
              onPress={() => toggleDay(idx)}
              activeOpacity={0.7}
            >
              <Text style={[s.dayAbbr, isDone && s.dayAbbrDone]}>{DAYS_ABBR[d]}</Text>
              <Text style={[s.dayNum, isDone && s.dayNumDone]}>{idx + 1}</Text>
              {isDone && <Text style={s.checkmark}>✓</Text>}
            </TouchableOpacity>
          );
        })}
      </View>

      {/* Gráfica de sueño */}
      <Text style={[s.sectionLabel, { marginTop: spacing.lg }]}>Horas de sueño registradas</Text>
      <View style={s.chartRow}>
        {sleepLog.map((h, i) => (
          <SleepBar key={i} hours={h} isToday={i === todayIdx} />
        ))}
      </View>
      <View style={s.chartLabels}>
        {DAYS_ABBR.concat(DAYS_ABBR).map((d, i) => (
          <Text key={i} style={s.chartLabel}>{d}</Text>
        ))}
      </View>

      {/* Registro diario */}
      <View style={s.logCard}>
        <Text style={s.logTitle}>Registrar horas dormidas hoy</Text>
        <View style={s.logRow}>
          <TextInput
            style={s.logInput}
            value={logInput}
            onChangeText={setLogInput}
            placeholder="ej. 7.5"
            placeholderTextColor={colors.textMuted}
            keyboardType="decimal-pad"
          />
          <TouchableOpacity style={s.logBtn} onPress={logSleep} activeOpacity={0.85}>
            <Text style={s.logBtnText}>Guardar</Text>
          </TouchableOpacity>
        </View>
      </View>

      <View style={{ height: 40 }} />
    </ScrollView>
  );
}

